INSERT INTO questions (subject, topic, difficulty, question_text, choices, correct_answer, explanation, exam_type) VALUES
('General Education','English','easy','Each of the students _____ expected to submit a report by Friday.','[{"key":"A","text":"are"},{"key":"B","text":"is"},{"key":"C","text":"were"},{"key":"D","text":"have been"}]','B','The indefinite pronoun "each" is always singular and takes a singular verb "is".','secondary'),
('General Education','English','easy','Between you and _____, the answer is obvious.','[{"key":"A","text":"I"},{"key":"B","text":"myself"},{"key":"C","text":"me"},{"key":"D","text":"mine"}]','C','Prepositions take object pronouns. "Me" is the correct object form after "between."','secondary'),
('General Education','English','medium','By the time the principal arrived, the students _____ already begun the activity.','[{"key":"A","text":"have"},{"key":"B","text":"has"},{"key":"C","text":"had"},{"key":"D","text":"will have"}]','C','The past perfect "had begun" is used for an action completed before another past action.','secondary'),
('General Education','English','medium','Which sentence has a dangling modifier?','[{"key":"A","text":"Running quickly, Maria caught the bus."},{"key":"B","text":"Running quickly, the bus was missed."},{"key":"C","text":"The teacher, who was late, apologized."},{"key":"D","text":"He finished his homework before dinner."}]','B','A dangling modifier has no clear subject; the bus is not running — making "running quickly" a dangling modifier.','secondary'),
('General Education','English','easy','In the sentence "She sings beautifully," the word "beautifully" is a/an:','[{"key":"A","text":"adjective"},{"key":"B","text":"adverb"},{"key":"C","text":"noun"},{"key":"D","text":"verb"}]','B','"Beautifully" modifies the verb "sings," making it an adverb.','secondary'),
('General Education','English','easy','Which sentence demonstrates correct subject-verb agreement?','[{"key":"A","text":"The team are playing well."},{"key":"B","text":"Neither the students nor the teacher were present."},{"key":"C","text":"The news are shocking."},{"key":"D","text":"The committee has reached a decision."}]','D','Collective nouns like "committee" take singular verbs when acting as one unit.','secondary'),
('General Education','English','medium','Choose the sentence with correct parallel structure.','[{"key":"A","text":"She likes to swim, hiking, and to run."},{"key":"B","text":"She likes swimming, hiking, and running."},{"key":"C","text":"She likes to swim, hike, and running."},{"key":"D","text":"She likes swim, hike, and run."}]','B','Parallel structure requires all listed items to be in the same grammatical form — here, all gerunds.','secondary'),
('General Education','English','easy','Which word is an example of a common noun?','[{"key":"A","text":"Manila"},{"key":"B","text":"Rizal"},{"key":"C","text":"teacher"},{"key":"D","text":"Monday"}]','C','A common noun names a general person, place, or thing. "Teacher" is a general word, unlike the proper nouns Manila, Rizal, and Monday.','secondary'),
('General Education','English','medium','Identify the correct use of the apostrophe.','[{"key":"A","text":"The student''s books are on the desk. (one student)"},{"key":"B","text":"The students'' book are on the desk."},{"key":"C","text":"The students book''s are on the desk."},{"key":"D","text":"The students''s books are on the desk."}]','A','For singular possession, use apostrophe + s ("student''s"). For plural, add the apostrophe after the s ("students''").','secondary'),
('General Education','English','hard','Which sentence correctly uses the subjunctive mood?','[{"key":"A","text":"If I was you, I would apologize."},{"key":"B","text":"She wishes she was taller."},{"key":"C","text":"If I were you, I would apologize."},{"key":"D","text":"He insists that she goes first."}]','C','The subjunctive "were" is used in contrary-to-fact conditions. "If I were you" is the correct subjunctive form.','secondary'),
('General Education','English','easy','The sentence "The dog bit the man" is in the _____ voice.','[{"key":"A","text":"passive"},{"key":"B","text":"active"},{"key":"C","text":"subjunctive"},{"key":"D","text":"imperative"}]','B','In the active voice, the subject (dog) performs the action (bit) on the object (man).','secondary'),
('General Education','English','easy','Convert to passive voice: "The teacher checked the papers."','[{"key":"A","text":"The papers was checked by the teacher."},{"key":"B","text":"The papers were checked by the teacher."},{"key":"C","text":"The teacher was checked the papers."},{"key":"D","text":"The papers had checked by the teacher."}]','B','The passive voice places the object (papers) first; use "were" because "papers" is plural.','secondary'),
('General Education','English','medium','Which sentence uses a semicolon correctly?','[{"key":"A","text":"I want to go; but it is raining."},{"key":"B","text":"She studied hard; therefore, she passed."},{"key":"C","text":"He likes: reading; and writing."},{"key":"D","text":"We went to the mall; bought shoes."}]','B','A semicolon can connect two independent clauses, especially when followed by a conjunctive adverb like "therefore."','secondary'),
('General Education','English','medium','Which is an example of a complex sentence?','[{"key":"A","text":"She sings and dances."},{"key":"B","text":"Maria went home."},{"key":"C","text":"Although it was raining, they continued playing."},{"key":"D","text":"He left; she stayed."}]','C','A complex sentence has one independent clause and at least one dependent clause. "Although it was raining" is a dependent clause.','secondary'),
('General Education','English','easy','What type of sentence is this: "Stop talking!"','[{"key":"A","text":"Declarative"},{"key":"B","text":"Interrogative"},{"key":"C","text":"Exclamatory"},{"key":"D","text":"Imperative"}]','D','An imperative sentence gives a command or request. The subject "you" is implied.','secondary'),
('General Education','English','medium','Choose the correct verb form: "The data _____ been analyzed."','[{"key":"A","text":"has"},{"key":"B","text":"have"},{"key":"C","text":"are"},{"key":"D","text":"is"}]','B','"Data" is the plural form of "datum" and takes a plural verb "have."','secondary'),
('General Education','English','hard','Identify the misplaced modifier in: "She almost drove her children to school every day."','[{"key":"A","text":'"almost" should come after "drove"'},{"key":"B","text":'"almost" is correctly placed'},{"key":"C","text":'"almost" should come before "every"'},{"key":"D","text":"There is no error"}]','C','The intended meaning is she drove them nearly every day; "almost" should modify "every day" — "She drove her children to school almost every day."','secondary'),
('General Education','English','easy','Which sentence is grammatically correct?','[{"key":"A","text":"Me and my friend went to school."},{"key":"B","text":"My friend and I went to school."},{"key":"C","text":"My friend and me went to school."},{"key":"D","text":"I and my friend went to school."}]','B','Subjects of a sentence use nominative pronouns. "I" is correct; conventionally the other person is named first.','secondary'),
('General Education','English','medium','Which pair of words are homophones?','[{"key":"A","text":"their / there / they''re"},{"key":"B","text":"bear / bare / beer"},{"key":"C","text":"right / write / wright"},{"key":"D","text":"All of the above"}]','D','All three groups contain homophones — words that sound alike but are spelled differently and have different meanings.','secondary'),
('General Education','English','easy','The prefix "un-" in "unhappy" means:','[{"key":"A","text":"very"},{"key":"B","text":"not"},{"key":"C","text":"again"},{"key":"D","text":"before"}]','B','The prefix "un-" indicates negation or the opposite, so "unhappy" means not happy.','secondary'),
('General Education','English','medium','What is the noun form of the adjective "strong"?','[{"key":"A","text":"strongly"},{"key":"B","text":"strengthen"},{"key":"C","text":"strength"},{"key":"D","text":"stronger"}]','C','"Strength" is the noun form. "Strongly" is an adverb and "strengthen" is a verb.','secondary'),
('General Education','English','easy','Identify the conjunction in: "She studied hard, yet she failed."','[{"key":"A","text":"studied"},{"key":"B","text":"yet"},{"key":"C","text":"she"},{"key":"D","text":"hard"}]','B','"Yet" is a coordinating conjunction (part of FANBOYS) that connects two independent clauses.','secondary'),
('General Education','English','hard','Which sentence contains a gerund phrase used as a subject?','[{"key":"A","text":"He enjoys playing basketball."},{"key":"B","text":"Playing basketball improves coordination."},{"key":"C","text":"She is playing basketball now."},{"key":"D","text":"To play basketball requires skill."}]','B','In option B, "Playing basketball" is a gerund phrase functioning as the subject of the sentence.','secondary'),
('General Education','English','medium','Choose the sentence that uses commas correctly.','[{"key":"A","text":"I bought apples oranges and bananas."},{"key":"B","text":"I bought, apples, oranges, and bananas."},{"key":"C","text":"I bought apples, oranges, and bananas."},{"key":"D","text":"I bought apples oranges, and bananas."}]','C','Items in a series are separated by commas; the Oxford comma before "and" is used in option C.','secondary'),
('General Education','English','medium','The word "quickly" in "She ran quickly" is a/an:','[{"key":"A","text":"adjective"},{"key":"B","text":"adverb"},{"key":"C","text":"preposition"},{"key":"D","text":"conjunction"}]','B','"Quickly" modifies the verb "ran," describing how the action was done — making it an adverb.','secondary'),
('General Education','English','easy','Which sentence uses the correct article?','[{"key":"A","text":"She is an honest woman."},{"key":"B","text":"She is a honest woman."},{"key":"C","text":"She is the honest woman."},{"key":"D","text":"She is honest woman."}]','A','Use "an" before words beginning with a vowel sound. "Honest" begins with a silent "h," so its first sound is the vowel /ɒ/.','secondary'),
('General Education','English','medium','Identify the indirect object: "The teacher gave the students books."','[{"key":"A","text":"teacher"},{"key":"B","text":"gave"},{"key":"C","text":"students"},{"key":"D","text":"books"}]','C','The indirect object (students) is the recipient of the direct object (books). "To whom were the books given? — the students."','secondary'),
('General Education','English','hard','Which sentence correctly uses "affect" vs. "effect"?','[{"key":"A","text":"The rain effected our plans."},{"key":"B","text":"The medicine had a positive affect."},{"key":"C","text":"Stress can affect your health."},{"key":"D","text":"His speech had a great affect on the crowd."}]','C','"Affect" is typically a verb meaning to influence; "effect" is typically a noun meaning result. "Stress can affect your health" uses the verb correctly.','secondary'),
('General Education','English','medium','Which is the plural form of "criterion"?','[{"key":"A","text":"criterions"},{"key":"B","text":"criterias"},{"key":"C","text":"criteria"},{"key":"D","text":"criterium"}]','C','"Criteria" is the correct plural of "criterion," which comes from Greek. "Criteria" is already plural and should not have an "s" added.','secondary'),
('General Education','English','easy','What punctuation mark ends an interrogative sentence?','[{"key":"A","text":"Period"},{"key":"B","text":"Exclamation point"},{"key":"C","text":"Question mark"},{"key":"D","text":"Comma"}]','C','An interrogative sentence asks a question and is always followed by a question mark.','secondary'),
('General Education','English','medium','Select the sentence with an error in pronoun-antecedent agreement.','[{"key":"A","text":"Each student must bring their own pencil."},{"key":"B","text":"Everyone should submit his or her assignment."},{"key":"C","text":"The team celebrated its victory."},{"key":"D","text":"All students submitted their projects."}]','A','Traditional grammar requires a singular pronoun for "each" (his or her), though "their" as a singular is increasingly accepted.','secondary'),
('General Education','English','easy','The root word "port" in "transport" means:','[{"key":"A","text":"to carry"},{"key":"B","text":"to move fast"},{"key":"C","text":"to stop"},{"key":"D","text":"to go"}]','A','The Latin root "port" means to carry. Transport, import, export, and portable all share this meaning.','secondary'),
('General Education','English','medium','Identify the type of phrase: "the tall woman in the red dress."','[{"key":"A","text":"Verb phrase"},{"key":"B","text":"Adverb phrase"},{"key":"C","text":"Noun phrase"},{"key":"D","text":"Prepositional phrase"}]','C','A noun phrase has a noun ("woman") as its head word, along with modifiers ("the tall") and a prepositional phrase.','secondary'),
('General Education','English','hard','Which sentence demonstrates the correct use of a restrictive relative clause?','[{"key":"A","text":"My sister, who lives in Cebu, is a nurse."},{"key":"B","text":"The book that I borrowed is overdue."},{"key":"C","text":"Mr. Santos, that I admire, retired last year."},{"key":"D","text":"She returned the bag, that was expensive."}]','B','Restrictive clauses (no commas) use "that" and are essential to the sentence meaning. Non-restrictive clauses use "which" or "who" with commas.','secondary'),
('General Education','English','medium','The suffix "-tion" in "education" makes it a/an:','[{"key":"A","text":"verb"},{"key":"B","text":"adverb"},{"key":"C","text":"adjective"},{"key":"D","text":"noun"}]','D','The suffix "-tion" converts verbs to nouns. "Educate" (verb) → "education" (noun).','secondary'),
('General Education','English','easy','Which of the following is a linking verb?','[{"key":"A","text":"run"},{"key":"B","text":"jump"},{"key":"C","text":"seems"},{"key":"D","text":"throw"}]','C','Linking verbs connect the subject to a predicate noun or adjective. "Seems," "appears," "feels," and forms of "be" are linking verbs.','secondary'),
('General Education','English','medium','Choose the sentence that is in the correct tense sequence.','[{"key":"A","text":"She said that she will come tomorrow."},{"key":"B","text":"She said that she would come the next day."},{"key":"C","text":"She says that she would come tomorrow."},{"key":"D","text":"She said that she comes tomorrow."}]','B','Sequence of tenses: the past "said" requires the past conditional "would" in the subordinate clause.','secondary'),
('General Education','English','hard','What is a "zeugma"?','[{"key":"A","text":"Repetition of a word at the end of successive clauses"},{"key":"B","text":"A figure of speech using one word to modify two or more words in different ways"},{"key":"C","text":"Exaggeration for emphasis"},{"key":"D","text":"Substitution of a mild expression for a harsh one"}]','B','A zeugma uses one word (typically a verb) to govern two or more words or phrases with different meanings, e.g., "She broke his car and his heart."','secondary'),
('General Education','English','easy','What does "omnivore" mean based on its word parts?','[{"key":"A","text":"Plant-eater"},{"key":"B","text":"Meat-eater"},{"key":"C","text":"Eats everything"},{"key":"D","text":"Does not eat"}]','C','"Omni" means all/everything and "vore" means to eat; an omnivore eats both plants and animals.','secondary'),
('General Education','English','medium','Identify the appositive in: "My best friend, a talented singer, won the contest."','[{"key":"A","text":"My best friend"},{"key":"B","text":"a talented singer"},{"key":"C","text":"won the contest"},{"key":"D","text":"the contest"}]','B','An appositive renames or re-identifies a noun. "A talented singer" renames "my best friend."','secondary'),
('General Education','English','easy','Which sentence uses "its" correctly?','[{"key":"A","text":"The dog wagged it''s tail."},{"key":"B","text":"Its raining outside."},{"key":"C","text":"The company increased its profits."},{"key":"D","text":"It''s logo is blue."}]','C','"Its" (no apostrophe) is a possessive pronoun. "It''s" (with apostrophe) is a contraction of "it is."','secondary'),
('General Education','English','medium','The word "antebellum" refers to the period:','[{"key":"A","text":"After a war"},{"key":"B","text":"During a war"},{"key":"C","text":"Before a war"},{"key":"D","text":"Caused by a war"}]','C','The Latin prefix "ante-" means before, and "bellum" means war; antebellum means before the war.','secondary'),
('General Education','English','easy','Which sentence is a compound sentence?','[{"key":"A","text":"Maria went to school."},{"key":"B","text":"Although tired, she studied."},{"key":"C","text":"She studied, and she passed."},{"key":"D","text":"She studied to pass the exam."}]','C','A compound sentence has two or more independent clauses joined by a coordinating conjunction (FANBOYS). "She studied" and "she passed" are both independent clauses.','secondary'),
('General Education','English','medium','Which word means the same as "perspicacious"?','[{"key":"A","text":"Dull"},{"key":"B","text":"Shrewd"},{"key":"C","text":"Lazy"},{"key":"D","text":"Clumsy"}]','B','"Perspicacious" means having a ready insight into things; shrewd. Antonym: dull or obtuse.','secondary'),
('General Education','English','hard','In rhetoric, "anaphora" is the repetition of a word or phrase:','[{"key":"A","text":"At the end of successive clauses"},{"key":"B","text":"At the beginning of successive clauses"},{"key":"C","text":"In the middle of a sentence"},{"key":"D","text":"As a concluding statement"}]','B','Anaphora is a rhetorical device where words are repeated at the start of successive clauses. Example: "We shall fight on the beaches, we shall fight on the landing grounds..."','secondary'),
('General Education','English','medium','Choose the antonym of "loquacious."','[{"key":"A","text":"Talkative"},{"key":"B","text":"Eloquent"},{"key":"C","text":"Taciturn"},{"key":"D","text":"Verbose"}]','C','"Loquacious" means very talkative. Its antonym is "taciturn" — reserved, saying little.','secondary'),
('General Education','English','easy','The prefix "mis-" in "misunderstand" means:','[{"key":"A","text":"before"},{"key":"B","text":"wrongly or badly"},{"key":"C","text":"again"},{"key":"D","text":"under"}]','B','The prefix "mis-" means wrongly or badly, as in misunderstand (understand wrongly) or misbehave (behave badly).','secondary'),
('General Education','English','medium','Which figure of speech is used in "The world is a stage"?','[{"key":"A","text":"Simile"},{"key":"B","text":"Hyperbole"},{"key":"C","text":"Metaphor"},{"key":"D","text":"Alliteration"}]','C','A metaphor makes a direct comparison without using "like" or "as." "The world is a stage" (Shakespeare) directly equates the two.','secondary'),
('General Education','English','easy','A word that imitates the sound it represents is called:','[{"key":"A","text":"Alliteration"},{"key":"B","text":"Onomatopoeia"},{"key":"C","text":"Assonance"},{"key":"D","text":"Consonance"}]','B','Onomatopoeia is the use of words that imitate sounds, such as "buzz," "hiss," "click," and "splash."','secondary'),
('General Education','English','medium','Which is the correct comparative form of "bad"?','[{"key":"A","text":"badder"},{"key":"B","text":"more bad"},{"key":"C","text":"worse"},{"key":"D","text":"worser"}]','C','"Bad" has an irregular comparative form: bad → worse → worst.','secondary');
